import React, { useState, useEffect } from 'react';
import { Bell, Settings, User, ChevronDown, Moon, Sun, LogOut, BookOpen, GraduationCap } from 'lucide-react';
import Course from './Course.jsx';
import InstructorDashboard from './InstructorDashboard.jsx';
import StudentDashboard from './components/StudentDashboard.jsx';
import LoginModal from './components/LoginModal.jsx';
import LoadingSpinner from './components/LoadingSpinner.jsx';
import ErrorBoundary from './components/ErrorBoundary.jsx';
import { ToastProvider, useToast } from './components/Toast.jsx';
import { validateCourse } from './utils/validation.js';
import useCourseStore from './store/courseStore.js';
import useAuthStore from './store/authStore.js';
import dataService from './services/api.js';

const AppContent = () => {
  const [currentPage, setCurrentPage] = useState('courses');
  const [showUserMenu, setShowUserMenu] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const { showToast } = useToast();

  const { user, isAuthenticated, logout } = useAuthStore();
  const { courses, notifications, loading, error, setCourses, addCourse, updateCourse, deleteCourse, setLoading, setError, getStats, markNotificationRead } = useCourseStore();

  const stats = getStats();

  useEffect(() => {
    if (courses.length === 0) loadDefaultCourses();
    const darkMode = localStorage.getItem('darkMode') === 'true';
    setIsDarkMode(darkMode);
    if (darkMode) document.documentElement.classList.add('dark');

    // Close menus when clicking outside
    const handleClickOutside = (event) => {
      if (!event.target.closest('.notification-menu')) {
        setShowNotifications(false);
      }
      if (!event.target.closest('.user-menu')) {
        setShowUserMenu(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [courses.length]);

  const loadDefaultCourses = async () => {
    try {
      const response = await fetch('/api/courses.php', { credentials: 'include' });
      const data = await response.json();
      if (data.success) {
        setCourses(data.courses);
      } else {
        throw new Error('API failed');
      }
    } catch (error) {
      const defaultCourses = [
        {id:1,title:'Full Stack Web Development',desc:'Master HTML, CSS, JS, React, Node.js and build dynamic web apps.',level:'Intermediate',rating:'4.8',time:'8h 30m',cat:'development',instructor:'John Parker',img:'https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=400&h=200&fit=crop',price:99,enrolled:1250,progress:65},
        {id:2,title:'Machine Learning Basics',desc:'Understand algorithms, train models, and deploy ML apps with Python.',level:'Advanced',rating:'4.9',time:'10h',cat:'ai',instructor:'Dr. Aisha Khan',img:'https://images.unsplash.com/photo-1581090700227-1e37b190418e?w=400&h=200&fit=crop',price:149,enrolled:890,progress:0},
        {id:3,title:'UI/UX Design for Beginners',desc:'Learn Figma, typography, wireframing, and design psychology.',level:'Beginner',rating:'4.6',time:'6h 45m',cat:'design',instructor:'Elena Rose',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=400&h=200&fit=crop',price:79,enrolled:2100,progress:100},
        {id:4,title:'Advanced React Development',desc:'Deep dive into React hooks, context, performance optimization, and testing.',level:'Advanced',rating:'4.9',time:'12h 15m',cat:'development',instructor:'Sarah Chen',img:'https://images.unsplash.com/photo-1633356122544-f134324a6cee?w=400&h=200&fit=crop',price:179,enrolled:756,progress:45},
        {id:5,title:'Digital Marketing Mastery',desc:'Learn SEO, social media marketing, content strategy, and analytics.',level:'Intermediate',rating:'4.7',time:'9h 20m',cat:'business',instructor:'Mike Rodriguez',img:'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=400&h=200&fit=crop',price:129,enrolled:1890,progress:78},
        {id:6,title:'Python for Data Science',desc:'Master pandas, numpy, matplotlib, and machine learning fundamentals.',level:'Intermediate',rating:'4.8',time:'11h 45m',cat:'ai',instructor:'Dr. Lisa Wang',img:'https://images.unsplash.com/photo-1526379095098-d400fd0bf935?w=400&h=200&fit=crop',price:159,enrolled:1456,progress:23},
